SQLLite.SQL:
				UPDATE CO_EVENTS COE
				SET	COE.BMS_TASK_NUMBER = ${param.bmsTask}
 				,	COE.STATS_MODULE 	= ${param.statsModule}
 				,	COE.AGE_CATEGORY 	= ${param.ageCategory}
				,	COE.CREATING_COURT 	= ${param.creatingCourt}
				,	COE.CREATING_SECTION= ${param.creatingSection}
				WHERE COE.CO_EVENT_SEQ 	= ${param.cOEventSeq}
